const popupImgs = [
  'data:image/png;base64,',
  'data:image/png;base64,',
  'data:image/png;base64,',
  'data:image/png;base64,',
  'data:image/png;base64,',
  'data:image/png;base64,',
];

    const titles = [
      '경고 - 피부 이상 감지됨',
      '오류 0x00FF0000',
      '당신의 피부를 분석 중...',
      'WARNING.exe',
      '지금 당장 확인하세요',
      '압출 권장 알림',
    ];

    // 커서
    const cursor = document.getElementById('custom-cursor');
    document.addEventListener('mousemove', function(e) {
      cursor.style.left = e.clientX + 'px';
      cursor.style.top = e.clientY + 'px';
    });

    // 배경 텍스트
    const words = ['징그러워 더러워 싫어 그치만 보고싶어 짜증나 왜 자꾸봐 역겨워 멈출수가없어 싫은데좋아 보지마 또봤잖아'];
    const wrap = document.getElementById('bgTextWrap');
    const rowCount = Math.ceil(window.innerHeight / 39) + 2;
    for (let i = 0; i < rowCount; i++) {
      const span = document.createElement('span');
      span.classList.add('bg-row');
      const offset = i % words[0].split(' ').length;
      const wordList = words[0].split(' ');
      const rotated = [...wordList.slice(offset), ...wordList.slice(0, offset)];
      const repeated = (rotated.join('  ') + '  ').repeat(6);
      span.textContent = repeated;
      span.style.animationDelay = (i * 0.3) + 's';
      wrap.appendChild(span);
    }

    document.getElementById('acneVideo').playbackRate = 3.0;
    document.getElementById('acneVideoZoom').playbackRate = 3.0;

    // 배경 텍스트 마우스 반응
    document.addEventListener('mousemove', function(e) {
      const rows = document.querySelectorAll('.bg-row');
      rows.forEach(function(row) {
        const rect = row.getBoundingClientRect();
        const rowCenter = rect.top + rect.height / 2;
        const dist = Math.abs(e.clientY - rowCenter);
        const maxDist = 150;
        if (dist < maxDist) {
          const scale = 1 + (1 - dist / maxDist) * 0.6;
          row.style.animation = 'none';
          row.style.transform = 'scaleX(' + scale + ')';
          row.style.transformOrigin = e.clientX + 'px center';
        } else {
          row.style.animation = '';
          row.style.transform = '';
        }
      });
    });

    // 확대 효과
    const videoWrap = document.getElementById('videoWrap');
    const zoomWrap = document.getElementById('zoom-wrap');
    const zoomVideo = document.getElementById('acneVideoZoom');
    const zoomScale = 10;
    const zoomSize = 700;

    videoWrap.addEventListener('mouseenter', function() {
      zoomWrap.style.display = 'block';
      cursor.style.width = '80px';
      cursor.style.height = '80px';
    });
    videoWrap.addEventListener('mouseleave', function() {
      zoomWrap.style.display = 'none';
      cursor.style.width = '20px';
      cursor.style.height = '20px';
    });
    videoWrap.addEventListener('mousemove', function(e) {
      const rect = videoWrap.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      zoomWrap.style.left = x + 'px';
      zoomWrap.style.top = y + 'px';
      const zx = -(x * zoomScale - zoomSize / 2);
      const zy = -(y * zoomScale - zoomSize / 2);
      zoomVideo.style.setProperty('--zx', zx + 'px');
      zoomVideo.style.setProperty('--zy', zy + 'px');
    });

    // 팝업 창 효과 — 랜딩 섹션에서만
    let lastPopupX = -999, lastPopupY = -999;
    const MIN_DIST = 30; // 이 거리만큼 움직여야 팝업 생성

    function spawnPopup(mouseX, mouseY) {
      const landing = document.getElementById('landingSection');
      const rect = landing.getBoundingClientRect();
      if (mouseY < rect.top || mouseY > rect.bottom) return;

      const popup = document.createElement('div');
      popup.classList.add('popup-window');

      const w = 180 + Math.random() * 120;
      const h = 140 + Math.random() * 80;
      const offsetX = (Math.random() - 0.5) * 300;
      const offsetY = (Math.random() - 0.5) * 300;
      const left = Math.max(0, Math.min(window.innerWidth - w, mouseX + offsetX));
      const top  = Math.max(0, Math.min(window.innerHeight - h, mouseY + offsetY));

      popup.style.cssText = `left:${left}px;top:${top}px;width:${w}px;height:${h}px;`;

      const titlebar = document.createElement('div');
      titlebar.classList.add('popup-titlebar');
      titlebar.innerHTML = `<span>${titles[Math.floor(Math.random() * titles.length)]}</span><div class="close-btn">✕</div>`;

      const img = document.createElement('img');
      img.src = popupImgs[Math.floor(Math.random() * popupImgs.length)];

      popup.appendChild(titlebar);
      popup.appendChild(img);
      document.body.appendChild(popup);

      setTimeout(() => popup.remove(), 1200);
    }

    document.addEventListener('mousemove', function(e) {
      const dx = e.clientX - lastPopupX;
      const dy = e.clientY - lastPopupY;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist > MIN_DIST) {
        const count = Math.floor(Math.random() * 3) + 1;
        for (let i = 0; i < count; i++) {
          setTimeout(() => spawnPopup(e.clientX, e.clientY), i * 60);
        }
        lastPopupX = e.clientX;
        lastPopupY = e.clientY;
      }
    });